"""A production-quality shopping cart implementation.

This module exposes a :class:`ShoppingCart` that manages line items, applies
discounts, and computes totals. It is deliberately free of any I/O so it can be
reused across CLIs, web handlers, or background jobs without modification.
"""

from __future__ import annotations

from abc import ABC, abstractmethod
from dataclasses import dataclass, replace
from decimal import Decimal

# Monetary values are modelled with ``Decimal`` to avoid binary floating-point
# rounding errors that are unacceptable in financial calculations.
Money = Decimal


class ShoppingCartError(Exception):
    """Base class for all errors raised by the shopping cart."""


class ItemNotFoundError(ShoppingCartError):
    """Raised when an operation targets a product that is not in the cart."""

    def __init__(self, product_name: str) -> None:
        super().__init__(f"No item named {product_name!r} exists in the cart.")
        self.product_name = product_name


class DuplicateItemError(ShoppingCartError):
    """Raised when adding a product that is already present in the cart."""

    def __init__(self, product_name: str) -> None:
        super().__init__(
            f"Item {product_name!r} is already in the cart; "
            "update its quantity instead of adding it again."
        )
        self.product_name = product_name


class InvalidPriceError(ShoppingCartError):
    """Raised when a unit price is zero or negative."""

    def __init__(self, unit_price: Money) -> None:
        super().__init__(f"Unit price must be greater than zero, got {unit_price}.")
        self.unit_price = unit_price


class InvalidQuantityError(ShoppingCartError):
    """Raised when a quantity is zero or negative."""

    def __init__(self, quantity: int) -> None:
        super().__init__(f"Quantity must be a positive integer, got {quantity}.")
        self.quantity = quantity


class InvalidDiscountError(ShoppingCartError):
    """Raised when a discount would be negative or exceed valid bounds."""


@dataclass(frozen=True)
class CartItem:
    """An immutable line item in the cart.

    Immutability guarantees the cart's internal state can only change through
    its public methods, never via an external reference to a stored item.
    """

    product_name: str
    unit_price: Money
    quantity: int

    @property
    def line_total(self) -> Money:
        """Return the cost of this line: ``unit_price * quantity``."""
        return self.unit_price * self.quantity


class DiscountStrategy(ABC):
    """Strategy describing how to reduce a subtotal.

    Encapsulating discounts behind an interface keeps :class:`ShoppingCart`
    closed for modification but open for extension (Open/Closed Principle):
    new discount types are added without touching the cart.
    """

    @abstractmethod
    def apply_to(self, subtotal: Money) -> Money:
        """Return the discount amount to subtract from ``subtotal``."""


@dataclass(frozen=True)
class PercentageDiscount(DiscountStrategy):
    """A discount expressed as a percentage of the subtotal."""

    percentage: Money

    def __post_init__(self) -> None:
        if not Decimal(0) <= self.percentage <= Decimal(100):
            raise InvalidDiscountError(
                f"Percentage must be between 0 and 100, got {self.percentage}."
            )

    def apply_to(self, subtotal: Money) -> Money:
        return subtotal * self.percentage / Decimal(100)


@dataclass(frozen=True)
class FlatDiscount(DiscountStrategy):
    """A discount expressed as a fixed monetary amount."""

    amount: Money

    def __post_init__(self) -> None:
        if self.amount < Decimal(0):
            raise InvalidDiscountError(
                f"Flat discount cannot be negative, got {self.amount}."
            )

    def apply_to(self, subtotal: Money) -> Money:
        # Never discount more than the subtotal itself.
        return min(self.amount, subtotal)


class ShoppingCart:
    """A shopping cart that holds line items and computes discounted totals.

    Items are keyed by product name, so each product appears at most once;
    purchasing more units is modelled by increasing an item's quantity rather
    than by storing duplicate entries.
    """

    def __init__(self) -> None:
        """Create an empty cart with no discount applied."""
        self._items_by_name: dict[str, CartItem] = {}
        self._discount: DiscountStrategy | None = None

    def add_item(
        self, product_name: str, unit_price: Money, quantity: int
    ) -> CartItem:
        """Add a new product to the cart and return the created line item.

        Raises:
            DuplicateItemError: If the product is already in the cart.
            InvalidPriceError: If ``unit_price`` is not positive.
            InvalidQuantityError: If ``quantity`` is not a positive integer.
        """
        normalized_name = self._normalize_name(product_name)
        if normalized_name in self._items_by_name:
            raise DuplicateItemError(normalized_name)

        self._validate_unit_price(unit_price)
        self._validate_quantity(quantity)

        item = CartItem(normalized_name, unit_price, quantity)
        self._items_by_name[normalized_name] = item
        return item

    def remove_item(self, product_name: str) -> None:
        """Remove a product from the cart.

        Raises:
            ItemNotFoundError: If the product is not in the cart.
        """
        item = self._require_item(product_name)
        del self._items_by_name[item.product_name]

    def update_quantity(self, product_name: str, quantity: int) -> CartItem:
        """Set the quantity of an existing product and return the updated item.

        Raises:
            ItemNotFoundError: If the product is not in the cart.
            InvalidQuantityError: If ``quantity`` is not a positive integer.
        """
        existing_item = self._require_item(product_name)
        self._validate_quantity(quantity)

        updated_item = replace(existing_item, quantity=quantity)
        self._items_by_name[updated_item.product_name] = updated_item
        return updated_item

    def apply_percentage_discount(self, percentage: Money) -> None:
        """Apply a percentage discount, replacing any existing discount.

        Raises:
            InvalidDiscountError: If ``percentage`` is outside ``[0, 100]``.
        """
        self._discount = PercentageDiscount(percentage)

    def apply_flat_discount(self, amount: Money) -> None:
        """Apply a flat monetary discount, replacing any existing discount.

        Raises:
            InvalidDiscountError: If ``amount`` is negative.
        """
        self._discount = FlatDiscount(amount)

    def remove_discount(self) -> None:
        """Remove any discount currently applied to the cart."""
        self._discount = None

    @property
    def subtotal(self) -> Money:
        """Return the sum of all line totals before any discount."""
        return sum(
            (item.line_total for item in self._items_by_name.values()),
            start=Money(0),
        )

    @property
    def discount_amount(self) -> Money:
        """Return the monetary value of the currently applied discount."""
        if self._discount is None:
            return Money(0)
        return self._discount.apply_to(self.subtotal)

    @property
    def total(self) -> Money:
        """Return the subtotal after subtracting the applied discount."""
        return self.subtotal - self.discount_amount

    def list_items(self) -> tuple[CartItem, ...]:
        """Return all line items as an immutable snapshot tuple."""
        return tuple(self._items_by_name.values())

    def clear(self) -> None:
        """Remove every item and any discount from the cart."""
        self._items_by_name.clear()
        self._discount = None

    def __len__(self) -> int:
        """Return the number of distinct products in the cart."""
        return len(self._items_by_name)

    def __contains__(self, product_name: object) -> bool:
        """Return whether a product name is present in the cart."""
        if not isinstance(product_name, str):
            return False
        return self._normalize_name(product_name) in self._items_by_name

    def _require_item(self, product_name: str) -> CartItem:
        """Return the stored item for ``product_name`` or raise if absent."""
        normalized_name = self._normalize_name(product_name)
        item = self._items_by_name.get(normalized_name)
        if item is None:
            raise ItemNotFoundError(normalized_name)
        return item

    @staticmethod
    def _normalize_name(product_name: str) -> str:
        """Trim surrounding whitespace so lookups are consistent."""
        return product_name.strip()

    @staticmethod
    def _validate_unit_price(unit_price: Money) -> None:
        """Reject prices that are zero or negative."""
        if unit_price <= Money(0):
            raise InvalidPriceError(unit_price)

    @staticmethod
    def _validate_quantity(quantity: int) -> None:
        """Reject quantities that are zero or negative."""
        if quantity <= 0:
            raise InvalidQuantityError(quantity)
```

### Design notes

- **Proper data structure** — items are immutable `CartItem` dataclasses (`frozen=True`), never raw dicts/tuples. Updates use `dataclasses.replace`, so stored state can't be mutated through an external reference.
- **SRP** — each method does one thing; validation, lookup, and normalization are extracted into small private helpers. Total/subtotal/discount are computed `@property` values rather than being recalculated ad hoc.
- **DRY** — `_require_item`, `_normalize_name`, `_validate_unit_price`, and `_validate_quantity` centralize the repeated logic used by add/remove/update.
- **Open/Closed** — discounts live behind a `DiscountStrategy` interface (`PercentageDiscount`, `FlatDiscount`). Adding a new discount type (e.g. "buy-one-get-one") needs no change to `ShoppingCart`. Discounts are mutually exclusive — applying one replaces the prior; `remove_discount()` clears it.
- **Specific exceptions** — a `ShoppingCartError` base with targeted subclasses (`ItemNotFoundError`, `DuplicateItemError`, `InvalidPriceError`, `InvalidQuantityError`, `InvalidDiscountError`), each carrying the offending value for programmatic handling. No bare `Exception`/`ValueError`.
- **Correctness of money** — `Decimal` throughout avoids float rounding errors; `FlatDiscount` is capped at the subtotal so the total never goes negative.
- **Type hints everywhere**, full docstrings, no `print`, no mutable default arguments. `__len__`/`__contains__` make the cart Pythonic to use.

